arguments.argument:
if global.gamePaused=false
{
  if AI_Action=0 //---------- AI ACTION: STAND AND LOOK AT PLAYER ----------
  {
    if x<oPlayer1.x
      image_xscale=1
    else
      image_xscale=-1
  }
  if AI_Action=2 //---------- AI ACTION: WALK BACK AND FORTH ----------
  {
    cycleTime+=1*gDeltaTime
    if cycleTime>=150
    {
      if storeSpd=0
      {
        storeSpd=xVel*-1
        storeImgSpd=image_speed
        image_speed=0
        xVel=0
      }
      waitTime+=1*gDeltaTime
      if waitTime>=40
      {
        xVel=storeSpd
        image_speed=storeImgSpd
        storeSpd=0
        waitTime=0
        cycleTime=0
      }
    }
  }
  
  if AI_Action>0
  {
    if xVel>0
      image_xscale=1
    else if xVel<0
      image_xscale=-1
  }
  
  if x<-16
    x=room_width+8
  else if x>room_width+16
    x=-8
    
  yVel+=0.2*gDeltaTime
  if isCollisionBottom(1)
    yVel=0
  if isCollisionLeft(1)
    xVel=runAcc
  if isCollisionRight(1)
    xVel=-runAcc
  moveTo(xVel*gDeltaTime,yVel*gDeltaTime)
  if isCollisionSolid()
    y-=2
}
